6.10 compare_and_swap() instruction으로 lock-free stack을 구현한 Figure 6.18의 program example이 race condition이 없는지 판단하라.

**Problem Details**

typedef struct node {
    value_t data;
    struct node *next;
} Node;

Node *top;

void push(value_t item) {
    Node *old_node;
    Node *new_node;
    new_node = malloc(sizeof(Node));
    new_node->data = item;
    do {
        old_node = top;
        new_node->next = old_node;
    } while (compare_and_swap(top, old_node, new_node) != old_node);
}

value_t pop() {
    Node *old_node;
    Node *new_node;
    do {
        old_node = top;
        if (old_node == NULL) return NULL;
        new_node = old_node->next;
    } while (compare_and_swap(top, old_node, new_node) != old_node);
    return old_node->data;
}

